function ModelNormalActivity:OnPrivilegeGiftResp(pb)
    --查看礼包状态
    local datas = pb.datas
    local _privilegeGift = self._privilegeGift or {}

    local oldData
    local buyIds = {}
    local isHaveBuy = true

    for i, v in ipairs(datas) do
        local info = StructPrivilegeData:New()
        info:CreateByPb(v)
        local refId = info.refId
        oldData = _privilegeGift[refId]
        _privilegeGift[refId] = info
        if oldData and (oldData.endTime ~= info.endTime) then
            if info.endTime == -1 or (oldData.endTime ~= -1 and info.endTime > oldData.endTime) then
                isHaveBuy = true
                buyIds[refId] = refId
            end
        end
    end
    self._privilegeGift = _privilegeGift

    self.autoRenew = pb.autoRenew

    local renewMap = {}
    local value = pb.multipleAutoRenew
    local strs = string.split(value, ',')
    for k, v in ipairs(strs) do
        local temps = string.split(v, ':')
        renewMap[tonumber(temps[1])] = tonumber(temps[2])
    end

    self._renewMap = renewMap

    FireEvent(EventNames.PRIVILEGE_REFRESH)
    if isHaveBuy then
        FireEvent(EventNames.PRIVILEGE_BUY_IDS, buyIds)
    end
    --gModelTowerDefence:StartPriviOverCheck()

    if not self._initPrivilegePop then
        self._initPrivilegePop = true
        self:InitPrivilegePop()
    end
end

function ModelNormalActivity:OnBuyPrivilegeGiftResp(pb)
    --购买特权礼包返回
    local refId = pb.refId          --特权商城数据表Id
    local ref = self:GetBIActivityPrivilegeGiftRefByRefId(refId)
