function ModelNormalActivity:GetPriviIdListByType(refId)
    if self._priviIdListMap then
        return self._priviIdListMap[refId]
    end

    local map = {}

    for k, v in pairs(GameTable.InnerActivityPrivilegeDataRef) do
        local list = map[v.type]
        if not list then
            list = {}
            map[v.type] = list
        end
        table.insert(list, v.refId)
    end

    self._priviIdListMap = map

    return map[refId]
