function ModelNormalActivity:SortAllRewardsShow(list)
    --- 统一排序函数
    local descriptSortMap = self._descriptSortMap
    if not descriptSortMap then
        descriptSortMap = {
            --- 正常获得
            [0] = -1,
            --- 创角限定
            [ModelNormalActivity.Descript_TimeLimit] = 0,
        }
        self._descriptSortMap = descriptSortMap
    end
    local sortFunc = self._sortAllRewardFunc
    if not sortFunc then
        sortFunc = function(a,b)
            local descriptA = a.descript or 0
            local descriptB = b.descript or 0
            local sortA = descriptSortMap[descriptA] or descriptA
            local sortB = descriptSortMap[descriptB] or descriptB
            return sortA < sortB
        end
        self._sortAllRewardFunc = sortFunc
    end
    table.sort(list,sortFunc)
end

function ModelNormalActivity:GetAllRewardShow(refId)
    local list = self:GetPriviRewardRef(refId)
    if not list then return end

    local dataList = {}

    local extraRewardList = {}
    --- 新增 额外返利的奖励图标
    local extraRewards = self:GetPrivilegeGiftExtraRewards(refId)
    if extraRewards and #extraRewards > 0 then
        for i,v in ipairs(extraRewards) do
            table.insert(extraRewardList,v)
        end
    end

    local key1 = 'showReward'
    local key2 = 'descriptionIcon'
    for k, v in ipairs(list) do
        local itemList = self:GetConfigValueImpl(ModelNormalActivity.InnerActivityPrivilegeRewardRef, v.refId, key1, self._parseFuncMap[key1])
        if itemList then
            local insList = {}
            local iconTagList = self:GetConfigValueImpl(ModelNormalActivity.InnerActivityPrivilegeRewardRef, v.refId, key2, self._parseFuncMap[key2])
            iconTagList = iconTagList or {}
            for idx, val in ipairs(itemList) do
                table.insert(insList,val)
            end
            for idx,val in ipairs(insList) do
                val.descript = iconTagList[idx] or 0
            end
            for idx,val in ipairs(extraRewardList) do
                table.insert(insList,val)
            end
            --- 显示顺序：正常 限时 每日每周等
            self:SortAllRewardsShow(insList)

            table.insert(dataList, insList)
        end
    end
    return dataList
end

function ModelNormalActivity:GetPrivilegeGiftExtraRewardInfo(refId)
    local ref = self:GetBIActivityPrivilegeGiftRefByRefId(refId)
    if not ref or string.isempty(ref.extraReward) then return end

    local initPrivilegeGiftExtraRewardInfo = self._initPrivilegeGiftExtraRewardInfo
    if not initPrivilegeGiftExtraRewardInfo then
        initPrivilegeGiftExtraRewardInfo = {}
        self._initPrivilegeGiftExtraRewardInfo = initPrivilegeGiftExtraRewardInfo
    end
    local info = initPrivilegeGiftExtraRewardInfo[refId]
    if not info then
        local descript = ModelNormalActivity.Descript_TimeLimit
        local extraReward = string.split(ref.extraReward,"|")
        local rewardList = LxDataHelper.ParseItem_3List(extraReward[2])
        for i,v in ipairs(rewardList) do
            v.descript = descript
        end
        local regTime = gModelPlayer:GetRegTime()
        local createRoleHour = checknumber(extraReward[1])
        local createRoleTime = createRoleHour * 3600
        local createRoleTipHour = checknumber(extraReward[3])
        local showTipTime = createRoleTipHour * 3600
        info = {
            regTime = regTime,
            createRoleHour = createRoleHour,
            createRoleTime = createRoleTime,
            createRoleEndTime = regTime + createRoleTime,
            rewardList = rewardList,
            createRoleTipHour = createRoleTipHour,
            showTipTime = showTipTime,
            showTipEndTime = regTime + showTipTime,
            showTipId = checknumber(extraReward[4]),
        }
        initPrivilegeGiftExtraRewardInfo[refId] = info
    end
    return info
end

--- 是否在创角时间内 -1：无配置，-2：超出时间，-3：已购买，0：在时间内
function ModelNormalActivity:CheckInCreateRoleTime(refId)
    local extraRewardInfo = self:GetPrivilegeGiftExtraRewardInfo(refId)
    if not extraRewardInfo then return -1 end

    if self:IsPrivilegeActive(refId) then return -3 end

    local limitTime = self:GetPrivilegeGiftExtraEndTime(refId)
    if not limitTime then return -1 end

    return limitTime >= GetTimestamp() and 0 or -2
end

function ModelNormalActivity:GetPrivilegeGiftExtraEndTime(refId)
    local extraRewardInfo = self:GetPrivilegeGiftExtraRewardInfo(refId)
    if not extraRewardInfo then return end
    return extraRewardInfo.createRoleEndTime
end

--- 是否在创角时间内提示 -1：无配置，-2：超出时间，-3：已购买，0：在时间内
function ModelNormalActivity:CheckInCreateRoleTip(refId)
    local extraRewardInfo = self:GetPrivilegeGiftExtraRewardInfo(refId)
    if not extraRewardInfo then return -1 end

    --- 已购买不弹窗
    if self:IsPrivilegeActive(refId) then return -3 end

    --- 不在创角时间内不处理
    if self:CheckInCreateRoleTime(refId) < 0 then return -2 end

    local curTime = GetTimestamp()
    local limitTipTime = extraRewardInfo.showTipEndTime
    local limitCreateRoleTime = extraRewardInfo.createRoleEndTime
    if limitTipTime <= curTime and curTime <= limitCreateRoleTime then
        return 0
    end
    return -2
end

function ModelNormalActivity:GetPrivilegeGiftExtraRewards(refId)
    local extraRewardInfo = self:GetPrivilegeGiftExtraRewardInfo(refId)
    if not extraRewardInfo then return {} end

    if self:CheckInCreateRoleTime(refId) < 0 then return {} end

    return extraRewardInfo.rewardList
end

function ModelNormalActivity:GetPriviShowData(refId)
    local dataList = {}
    for k, v in pairs(GameTable.InnerActivityPrivilegeDataRef) do
        if v.type == refId and v.rewardShow == 1 then
            table.insert(dataList, v)
        end
    end

    table.sort(dataList, function(a, b)
        return a.refId < b.refId
    end)

    return dataList[1]
end

function ModelNormalActivity:GetPriviRewardRef(refId)
    local dataList = {}
    for k, v in pairs(GameTable.InnerActivityPrivilegeDataRef) do
        if v.type == refId and v.rewardShow == 1 then
            table.insert(dataList, v)
        end
    end

    table.sort(dataList, function(a, b)
        return a.refId < b.refId
    end)

    if #dataList == 0 then
        return
    end

    local list = {}

    local dayPast = gLGameLogin:GetServerOpenDay()
    local rewardRef = self:GetModelConfig(ModelNormalActivity.InnerActivityPrivilegeRewardRef)
    for k1, v1 in ipairs(dataList) do
        for k, v in pairs(rewardRef) do
            if v.type == v1.refId then
                if dayPast >= v.openDayMin and dayPast <= v.openDayMax then
                    table.insert(list, v)
                    break
                end
            end
        end

    end

    return list
end

function ModelNormalActivity:GetPriviRewardDesc(refId, isLast)
    local list = self:GetPriviRewardRef(refId)
    if not list and #list > 0 then
        return
    end
    local data = list[1]
    if isLast then
        data = list[#list]
    end
    return ccLngText(data.description1)
end

--开始 ：【T特权商城】删掉无用的参数和特权
--[[
function ModelNormalActivity:CheckShowIosBubble(priviId, priviDataId)
    if not CS.IsOSIos() then
        return false
    end

    local judge = self:GetPara("showRenewText")
    if not judge[priviId] then
        return false
    end

    local showDataRefId = self:GetBIActivityConfigRefByKey("returnDate")
    if showDataRefId ~= priviDataId then
        return false
    end

    local curServerId = gLGameLogin:GetActualServerId()
    local serverPara = self:GetBIActivityConfigRefByKey("returnServerId")
    local serverList = string.split(serverPara, ';')
    local isIn = false
    for k, v in ipairs(serverList) do
        local strs = string.split(v, ",")
        local startS = strs[1] and tonumber(strs[1])
        local endS = strs[2] and tonumber(strs[2])
        if startS and endS and curServerId >= startS and curServerId <= endS then
            isIn = true
            break
        end
    end

    if not isIn then
        return false
    end

    local isActive = self:IsPrivilegeActive(showDataRefId)
    local privilegeEndTime = self:GetPrivilegeEndTimeByRefId(showDataRefId)
    local privilegeStartTime = 0
    if privilegeEndTime > 0 then
        local dataRef = self:GetBIActivityPrivilegeDataRefByRefId(showDataRefId)
        local timeLast = dataRef.time * 60
        privilegeStartTime = privilegeEndTime - timeLast
    end

    local curTime = GetTimestamp()
    local isInTime = false
    local datePara = self:GetBIActivityConfigRefByKey("returnTime")
    local dateList = string.split(datePara, ';')
    for k, v in ipairs(dateList) do
        local strs = string.split(v, ",")
        local dateStart = strs[1]
        local dateEnd = strs[2]

        if not string.isempty(dateStart) and not string.isempty(dateEnd) then
            local startTime = LUtil.GetTimeFromStr(dateStart)
            local endTime = LUtil.GetTimeFromStr(dateEnd)
            if curTime >= startTime and curTime <= endTime then
                if not isActive then
                    if privilegeEndTime == 0 then
                        --没购买过
                        isInTime = true
                    else
                        if privilegeStartTime < startTime then
                            --该时间段内没购买过
                            isInTime = true
                        end
                    end
                end

                break
            end
        end
    end

    return isInTime
end
