--结束: 【T特权商城】删掉无用的参数和特权

function ModelNormalActivity:BuyPrivi(refId)
    local ref = self:GetBIActivityPrivilegeDataRefByRefId(refId)
    if not ref then
        return
    end
    local giftRef = self:GetBIActivityPrivilegeGiftRefByRefId(ref.type)
    if not giftRef then
        return
    end
    local giftName = ccLngText(giftRef.name)

    local isUseItemBuy = string.find(ref.expend, "=")

    if isUseItemBuy then
        -- 钻石购买
        local item = LxDataHelper.ParseItem_3(ref.expend)
        local itemId = item.itemId
        local dia = gModelItem:GetNumByRefId(itemId)
        local value = item.itemNum
        local func = function()
            if dia >= value then
                self:OnBuyPrivilegeGiftReq(ref.refId)
            else
                gModelGeneral:OpenGetWayWnd({ itemId = item.itemId })
            end
        end
        GF.OpenWnd("UIOrdinTip", {
            refId = 110002,
            func = func,
            para = { value, giftName },
            consume = { value, itemId }
        })
    else
        -- 付费购买
        local expendId = tonumber(ref.expend)
        local isAuto = self:IsAutoGiftMgr(refId)
        if isAuto then
            expendId = string.isempty(ref.expendExtra) and ref.expend or ref.expendExtra
            expendId = tonumber(expendId)
        end

        gModelPay:GiftPayCtrl(ref.refId, expendId, ModelPay.PAY_TYPE_GIFT, ModelPay.PAY_GIFT_PRIVILEGE, nil, nil, isAuto)
    end
end

function ModelNormalActivity:BuyFreePrivi(refId)
    --屏蔽欧美配置
    if true then
        return
    end

    local firstExpend1 = gModelNormalActivity:GetPara("firstExpend1")
