    end

    local ref = self:GetBIActivityPrivilegeDataRefByRefId(refId)
    if not ref then
        return
    end

    local expendId = tonumber(ref.expend)

    local isAuto = self:IsAutoGiftMgr(refId)
    --if isAuto then
    --    expendId = string.isempty(ref.expendExtra) and ref.expend or ref.expendExtra
    --    expendId = tonumber(expendId)
    --end
    --gModelPay:GiftPayCtrl(ref.refId,expendId,ModelPay.PAY_TYPE_GIFT,ModelPay.PAY_GIFT_PRIVILEGE,nil,nil,isAuto)

    gModelPay:GiftPayCtrl(refId, welfareId, ModelPay.PAY_TYPE_GIFT, ModelPay.PAY_GIFT_PRIVILEGE, nil, nil, isAuto, true)
end

function ModelNormalActivity:IsAutoGiftMgr(refId)
    local ref = self:GetBIActivityPrivilegeDataRefByRefId(refId)
    if not ref then
        return false
    end

    local giftRef = self:GetBIActivityPrivilegeGiftRefByRefId(ref.type)
    if not giftRef then
        return false
    end

    local isAuto = false
    if gLGameLanguage:IsForeignVietnamOrAmericaRegion() then
        isAuto = self:IsUSARegionAutoGift(giftRef.refId)
    elseif gLGameLanguage:IsHmtRegion() then
        isAuto = false
    elseif gLGameLanguage:IsKoreaRegion() then
        isAuto = false
    else
        isAuto = self:IsAutoGift(giftRef.refId)
    end

    return isAuto
end

