function ModelNormalActivity:InitPrivilegePop()
    local privilegePopList = {}
    local privilegeGift = self._privilegeGift or {}
    local isShowTip

    local popMap = {}
    local pop = LPlayerPrefs.recordPrivilegePop or ""
    local pops = string.split(pop,"|")
    for i,v in ipairs(pops) do
        v = checknumber(v)
        popMap[v] = true
    end

    local curPops = {}
    ---@type boolean 按照发行要求调整，不弹提示弹窗，直接弹窗购买弹窗
    local isIssue = true
    for k,v in pairs(privilegeGift) do
        if not popMap[k] then
            isShowTip = self:CheckInCreateRoleTip(k) == 0
            if isShowTip then
                ---@type V_BIActivityPrivilegeDataRef[]
                local tempList = self:GetPriviIdListByType(k)
                if tempList and #tempList > 0 then
                    local actCnt = 0
                    for idx,val in ipairs(tempList) do
                        if not self:IsPrivilegeActive(val) then
                            actCnt = actCnt + 1
                        end
                    end
                    isShowTip = actCnt > 0
                else
                    isShowTip = false
                end
            end
            if isShowTip then
                local ref = self:GetBIActivityPrivilegeGiftRefByRefId(k)
                local extraRewardInfo = self:GetPrivilegeGiftExtraRewardInfo(k)
                if extraRewardInfo and ref then
                    local show = false
                    local funcId = tonumber(ref.openCondition)
                    if funcId and funcId > 0 and gModelFunctionOpen:CheckIsShow(funcId) then
                        show = true
                    end
                    if show then
                        if isIssue then
                            table.insert(privilegePopList,{
                                wndPara = {
                                    uiName = "UIWishPrigeBuyPop",
                                    ref = ref,
                                    defaultSort = 7223482,
                                }
                            })
                        else
                            local jumpId = ref.jumpId
                            table.insert(privilegePopList,{
                                serData = v,
                                wndPara = {
                                    showCDTime = extraRewardInfo.createRoleEndTime,
                                    refId = extraRewardInfo.showTipId,
                                    para = {ccLngText(ref.name)},
                                    func = function()
                                        if self:CheckInCreateRoleTime(k) ~= 0 then
                                            GF.ShowMessage(ccClientText(14221))
                                            return
                                        end
                                        if jumpId and jumpId > 0 then
                                            gModelFunctionOpen:Jump(jumpId,nil,nil,{
                                                privilegeGiftRef = ref
                                            })
                                        end
                                    end,
                                    defaultSort = 7223482,
                                }
                            })
                        end
                        table.insert(curPops,k)
                    end
                end
            end
        end
    end
    self._privilegePopList = privilegePopList

    if #curPops > 0 then
        local str = table.concat(curPops,"|")
        LPlayerPrefs.SetRecordPrivilegePop(str)
    end

    self:ShowPrivilegePop(isIssue)
end

function ModelNormalActivity:ShowPrivilegePop(isIssue)
    if self._showPrivilegePop then return end

    self._showPrivilegePop = true

    local privilegePopList = self._privilegePopList or {}
    if #privilegePopList < 1 then return end

    for i,v in ipairs(privilegePopList) do
        if isIssue then
            gModelGeneral:InsertPopActivityWnd(v.wndPara)
        else
            gModelGeneral:InsertPopWndPara(v.wndPara)
        end
    end
end


---@return boolean 是否展示 联络客服 按钮
function ModelNormalActivity:CheckShowCustomerBtn()
    if PRODUCT_G_VER and PRODUCT_G_VER > 0 then
        --- 提审环境屏蔽该功能
        if CS.IsWebGL() and LWxHelper.IsDouYinPlatform() then
            return true
        end
        return false
    end

    if gLGameLogin:IsOpenGm() then return true end

    if LGameCommon.ShowCustomerBtnRegion() then return true end

    return false
end


